*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

body {
  font-family: Inter, system-ui, sans-serif;
  font-size: 14px;
  background: #fff;
  color: #333;
  padding: 32px 40px;
  max-width: 1280px;
}

h1 {
  font-size: 22px;
  font-weight: 600;
  color: #1a1a2e;
  margin-bottom: 24px;
}

/* Filter bar */
.filter-bar {
  display: flex;
  align-items: flex-end;
  gap: 16px;
  flex-wrap: wrap;
  background: #f9f9fb;
  border: 1px solid #e8e8ef;
  border-radius: 8px;
  padding: 14px 16px;
  margin-bottom: 16px;
}
.filter-group { display: flex; flex-direction: column; gap: 4px; }
.filter-group label { font-size: 12px; color: #888; font-weight: 500; }
.filter-group select, .filter-group input[type="text"] {
  background: #f5f5f5;
  border: 1px solid #ddd;
  border-radius: 6px;
  padding: 6px 10px;
  font-size: 13px;
  min-width: 160px;
  color: #333;
}
.filter-group select:focus, .filter-group input:focus { outline: 2px solid #4a90d9; }

.checkboxes-group { display: flex; flex-direction: column; gap: 4px; }
.checkboxes-group label.group-label { font-size: 12px; color: #888; font-weight: 500; }
.checkboxes-row { display: flex; gap: 14px; align-items: center; margin-top: 2px; }
.checkbox-item { display: flex; align-items: center; gap: 5px; font-size: 13px; }
.checkbox-item input[type="checkbox"] { width: 14px; height: 14px; accent-color: #4a90d9; }

/* Toolbar */
.toolbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 12px;
}
.toolbar-left { display: flex; gap: 10px; align-items: center; }
.toolbar-right { display: flex; gap: 10px; align-items: center; }

/* Buttons */
.btn {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 7px 14px;
  border-radius: 6px;
  border: 1px solid transparent;
  font-size: 13px;
  font-weight: 500;
  cursor: pointer;
  text-decoration: none;
  transition: opacity 0.15s;
}
.btn:hover { opacity: 0.88; }
.btn-primary { background: #4a90d9; color: #fff; border-color: #4a90d9; }
.btn-primary:disabled, .btn-primary.disabled {
  background: #a8c8ed; border-color: #a8c8ed; cursor: default; opacity: 1;
}
.btn-secondary { background: #fff; color: #4a90d9; border-color: #4a90d9; }
.btn-success { background: #28a745; color: #fff; border-color: #28a745; }
.btn-light { background: #f5f5f5; color: #555; border-color: #ddd; }
.btn-link { background: none; border: none; color: #4a90d9; padding: 7px 4px; font-size: 13px; text-decoration: underline; cursor: pointer; }
.btn-sm { padding: 4px 10px; font-size: 12px; }

/* Table */
.table-wrap { border: 1px solid #e8e8ef; border-radius: 8px; overflow: hidden; }
table { width: 100%; border-collapse: collapse; }
thead { background: #f4f6fb; }
thead th {
  padding: 10px 14px;
  text-align: left;
  font-size: 12px;
  font-weight: 600;
  color: #666;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  border-bottom: 1px solid #e8e8ef;
}
thead th.center { text-align: center; }
tbody tr { border-bottom: 1px solid #f0f0f5; transition: background 0.1s; }
tbody tr:last-child { border-bottom: none; }
tbody tr:hover { background: #f9f9fb; }
tbody tr.selected { background: #eef4fc; }
td { padding: 10px 14px; font-size: 13px; color: #333; }
td.center { text-align: center; }
td input[type="checkbox"] { width: 14px; height: 14px; accent-color: #4a90d9; }

/* Badges */
.badge {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 3px 8px;
  border-radius: 4px;
  font-size: 11px;
  font-weight: 600;
}
.badge-available { background: #e6f4ea; color: #2e7d32; }
.badge-unavailable { background: #f5f5f5; color: #aaa; }

/* Avatar row */
.avatar-strip { display: flex; gap: 20px; align-items: center; margin-bottom: 20px; }
.avatar-item { display: flex; align-items: center; gap: 8px; }
.avatar-circle {
  width: 36px; height: 36px; border-radius: 50%;
  background: #c7d8f0; color: #2c5282;
  display: flex; align-items: center; justify-content: center;
  font-size: 13px; font-weight: 600;
}
.avatar-name { font-size: 13px; font-weight: 500; }
.avatar-role { font-size: 11px; color: #888; }

/* Result count */
.result-count { font-size: 12px; color: #888; margin-bottom: 8px; }

/* Period indicators */
.period-bar { display: flex; gap: 12px; margin-bottom: 24px; }
.period-pill {
  padding: 6px 14px; border-radius: 20px; font-size: 12px;
  border: 1px solid #ddd; color: #888; cursor: default;
}
.period-pill.active { background: #eef4fc; border-color: #4a90d9; color: #1a6bb5; font-weight: 600; }

/* Section header (for configure page) */
.section-card {
  border: 1px solid #e8e8ef;
  border-radius: 8px;
  overflow: hidden;
  margin-bottom: 24px;
}
.section-card-header {
  background: #f4f6fb;
  padding: 12px 20px;
  font-size: 14px;
  font-weight: 600;
  color: #444;
  border-bottom: 1px solid #e8e8ef;
}
.section-card-body { padding: 20px; }

/* Info note */
.info-note {
  background: #eef4fc;
  border-left: 3px solid #4a90d9;
  border-radius: 4px;
  padding: 10px 14px;
  font-size: 12px;
  color: #2c5f9a;
  margin-bottom: 20px;
}

/* Save row */
.save-row { display: flex; justify-content: flex-end; margin-top: 20px; }
